arguments.command:
# Generate the image using Alibaba DashScope (通义万相) text-to-image API
PROMPT="A vintage Chinese propaganda poster style portrait of a thoughtful man in a dark blue Zhongshan suit with glasses, gazing slightly upward against a painted sunset sky of orange, yellow and soft blue hues. Bold red Chinese characters at bottom. Retro poster aesthetic, cinematic lighting, textured paper feel."

TODAY=$(TZ=Asia/Shanghai date +%Y%m%d)
ID="DRAW-${TODAY}-00001"
OUTPUT_FILE="${HOME}/.openclaw/workspace-son/draw/${ID}.png"

# Call DashScope Wanxiang text-to-image API
curl -s -X POST "https://dashscope.aliyuncs.com/api/v1/services/aigc/text2image/image-synthesis" \
  -H "Authorization: Bearer ${DASHSCOPE_API_KEY}" \
  -H "Content-Type: application/json" \
  -H "X-DashScope-Async: enable" \
  -d '{
    "model": "wanx2.1-t2i-turbo",
    "input": {
      "prompt": '"$(echo "$PROMPT" | python3 -c 'import json,sys;print(json.dumps(sys.stdin.read().strip()))')"'
    },
    "parameters": {
      "size": "1024x1024",
      "n": 1
    }
  }' 2>&1 | python3 -m json.tool 2>&1 | head -40

